import{_ as e,o as d,c as r,a2 as a}from"./chunks/framework.Wufm-cgV.js";const x=JSON.parse('{"title":"数据源管理","description":"Provider 类型和配置","frontmatter":{"title":"数据源管理","description":"Provider 类型和配置"},"headers":[],"relativePath":"zh/guide/providers.md","filePath":"zh/guide/providers.md"}'),l={name:"zh/guide/providers.md"};function n(i,t,o,c,s,h){return d(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="数据源管理" tabindex="-1">数据源管理 <a class="header-anchor" href="#数据源管理" aria-label="Permalink to &quot;数据源管理&quot;">​</a></h1><h2 id="支持的类型" tabindex="-1">支持的类型 <a class="header-anchor" href="#支持的类型" aria-label="Permalink to &quot;支持的类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th style="text-align:center;">健康</th><th style="text-align:center;">延迟</th><th style="text-align:center;">成本</th><th style="text-align:center;">渠道管理</th></tr></thead><tbody><tr><td><code>direct</code></td><td>官方直连（OpenAI、Claude、Gemini、DeepSeek 等）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><code>aggregate</code></td><td>聚合平台（OpenRouter、API2D、OhMyGPT 等）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">手动</td><td style="text-align:center;">—</td></tr><tr><td><code>newapi</code></td><td>自建 New-API / One-API</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>litellm</code></td><td>LiteLLM 代理</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><code>custom</code></td><td>任何 OpenAI 兼容网关</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><h2 id="添加数据源" tabindex="-1">添加数据源 <a class="header-anchor" href="#添加数据源" aria-label="Permalink to &quot;添加数据源&quot;">​</a></h2><ol><li>进入 <strong>数据源</strong> → <strong>+ 添加</strong></li><li>选择 Provider 类型</li><li>填写 Base URL 和 API Key</li><li>指定可用模型</li><li>配置权重和优先级</li><li>点击 <strong>保存</strong></li></ol><h2 id="健康检测" tabindex="-1">健康检测 <a class="header-anchor" href="#健康检测" aria-label="Permalink to &quot;健康检测&quot;">​</a></h2><p>WebRouter 每 5 分钟自动检测 Provider 健康状态：</p><ul><li><strong>健康：</strong> 正常响应</li><li><strong>警告：</strong> 延迟较高或偶发失败</li><li><strong>不可用：</strong> 无响应，进入冷却</li></ul><p>不可用的 Provider 自动排除出路由。</p><h2 id="provider-状态" tabindex="-1">Provider 状态 <a class="header-anchor" href="#provider-状态" aria-label="Permalink to &quot;Provider 状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td><code>healthy</code></td><td>正常</td></tr><tr><td><code>warning</code></td><td>高延迟或性能下降</td></tr><tr><td><code>dead</code></td><td>不可达（冷却中）</td></tr><tr><td><code>unknown</code></td><td>尚未检测</td></tr><tr><td><code>auth_failed</code></td><td>认证错误</td></tr></tbody></table>',11)])])}const y=e(l,[["render",n]]);export{x as __pageData,y as default};
